  describe('invariant examples', () => {
    it("create-then-execute", async () => {
      const storage = createInMemoryStorage();
      const createResult0 = await interpret(stateGraphHandler.create({ state_schema: "test-s" }), storage);
      expect(createResult0.variant).toBe("ok");
      let graph = createResult0.output["graph"];
      let h = graph;
      const addNodeResult1 = await interpret(stateGraphHandler.addNode({ graph: h, id: "start", type: "agent", handler: "test-_" }), storage);
      expect(addNodeResult1.variant).toBe("ok");
      graph = addNodeResult1.output["graph"];
      const addNodeResult2 = await interpret(stateGraphHandler.addNode({ graph: h, id: "end", type: "agent", handler: "test-_" }), storage);
      expect(addNodeResult2.variant).toBe("ok");
      graph = addNodeResult2.output["graph"];
      const addEdgeResult3 = await interpret(stateGraphHandler.addEdge({ graph: h, source: "start", target: "end" }), storage);
      expect(addEdgeResult3.variant).toBe("ok");
      graph = addEdgeResult3.output["graph"];
      const setEntryPointResult4 = await interpret(stateGraphHandler.setEntryPoint({ graph: h, node_id: "start" }), storage);
      expect(setEntryPointResult4.variant).toBe("ok");
      graph = setEntryPointResult4.output["graph"];
      const setFinishPointResult5 = await interpret(stateGraphHandler.setFinishPoint({ graph: h, node_ids: ["end"] }), storage);
      expect(setFinishPointResult5.variant).toBe("ok");
      graph = setFinishPointResult5.output["graph"];
      const compileResult6 = await interpret(stateGraphHandler.compile({ graph: h }), storage);
      expect(compileResult6.variant).toBe("ok");
      graph = compileResult6.output["graph"];
      const thenResult0 = await interpret(stateGraphHandler.execute({ graph: h, initial_state: "{}" }), storage);
      expect(thenResult0.variant).toBe("ok");
    });

  });

  describe('action contracts (PBT)', () => {
    it('create handles empty input: ', async () => {
      if (typeof stateGraphHandler.create !== 'function') return;
      const storage = createInMemoryStorage();
      const result = await safeInvoke(async () => await interpret(stateGraphHandler.create({  }), storage));
      // Empty input should produce a defined result with a variant
      expect(result).toBeDefined();
      if (result.variant !== undefined) {
        expect(typeof result.variant).toBe('string');
      }
    });

    it('create ensures on ok: ', async () => {
      if (typeof stateGraphHandler.create !== 'function') return;
      let seen = false;
      await fc.assert(
        fc.asyncProperty(
          fc.record({ state_schema: fc.string({ minLength: 1, maxLength: 50 }) }),
          async (input) => {
            const storage = createInMemoryStorage();
            const result = await safeInvoke(async () => {
              const program = stateGraphHandler.create(input as Record<string, unknown>);
              return interpret(program, storage);
            });
            if (result?.variant === "ok") {
              seen = true;
              expect(result.output).toBeDefined();
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

